mapper.select:
SELECT A.PROP_CD , A.PROP_NM , A.PROP_TYPE , CASE A.PROP_TYPE WHEN 'APT' THEN '아파트' WHEN 'OFFICETEL' THEN '오피스텔' WHEN 'SHOP' THEN '상가' WHEN 'OFFICE' THEN '사무실' ELSE '' END AS PROP_TYPE_NM , A.DEAL_TYPE , CASE A.DEAL_TYPE WHEN 'SELL' THEN '매매' WHEN 'JEONSE' THEN '전세' WHEN 'WOLSE' THEN '월세' WHEN 'RENT' THEN '임대' ELSE '' END AS DEAL_TYPE_NM , A.SELL_PRICE , A.DEPOSIT , A.MONTHLY_RENT , A.AREA_EXCLUSIVE , A.ROOM_CNT , A.FLOOR_NO , A.ADDRESS , A.ADDRESS_DTL , A.LAT , A.LNG , A.BADGE_TYPE , A.SOLD_YN , DATE_FORMAT(A.RGT_DTM, '%Y-%m-%d') AS RGT_DTM FROM TB_PROPERTY A WHERE A.DEL_YN = 'N' AND A.USE_YN = 'Y' AND A.SOLD_YN = 'N' AND A.LAT IS NOT NULL AND A.LNG IS NOT NULL
AND A.LAT BETWEEN #{swLat} AND #{neLat} AND A.LNG BETWEEN #{swLng} AND #{neLng}
AND A.PROP_TYPE = #{propType}
AND A.DEAL_TYPE = #{dealType}
ORDER BY A.RGT_DTM DESC LIMIT 100

SELECT A.PROP_CD , A.PROP_NM , A.PROP_TYPE , CASE A.PROP_TYPE WHEN 'APT' THEN '아파트' WHEN 'OFFICETEL' THEN '오피스텔' WHEN 'SHOP' THEN '상가' WHEN 'OFFICE' THEN '사무실' ELSE '' END AS PROP_TYPE_NM , A.DEAL_TYPE , CASE A.DEAL_TYPE WHEN 'SELL' THEN '매매' WHEN 'JEONSE' THEN '전세' WHEN 'WOLSE' THEN '월세' WHEN 'RENT' THEN '임대' ELSE '' END AS DEAL_TYPE_NM , A.SELL_PRICE , A.DEPOSIT , A.MONTHLY_RENT , A.AREA_EXCLUSIVE , A.ROOM_CNT , A.FLOOR_NO , A.ADDRESS , A.BADGE_TYPE , A.SOLD_YN , A.ATCH_FILE_KEY , (SELECT CONCAT(F.SAVE_PATH, '/', F.SAVE_FILE_NM) FROM TB_UPLD_FILE F WHERE F.UPLD_FILE_CD COLLATE utf8mb4_unicode_ci = A.ATCH_FILE_KEY AND F.DEL_YN = 'N' ORDER BY F.FILE_SEQ ASC LIMIT 1) AS THUMB_PATH , DATE_FORMAT(A.RGT_DTM, '%Y-%m-%d') AS RGT_DTM FROM TB_PROPERTY A WHERE A.DEL_YN = 'N' AND A.USE_YN = 'Y'
AND A.PROP_TYPE = UPPER(#{propType})
AND A.DEAL_TYPE = #{dealType}
AND (A.PROP_NM LIKE CONCAT('%', #{keyword}, '%') OR A.ADDRESS LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY CASE A.SOLD_YN WHEN 'N' THEN 0 ELSE 1 END ASC, A.RGT_DTM DESC LIMIT ${offset}, ${pageSize}
